VALUES
  ('optometrist-moex-01104', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光人員的執業執照，下列敘述何者正確？', '["驗光人員執業，應每3年接受一定時數之繼續教育，始得辦理執業執照更新", "繼續教育之課程內容、積分、實施方式、完成繼續教育之認定由在地直轄市、縣（市）主管機關定之", "驗光人員應向衛生福利部申請執業登記，領有執業執照，始得執業", "驗光人員執業以一處為限，但機構間之支援或經事先報准者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01105', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何種隱形眼鏡配戴屬於驗光師的業務範圍？', '["近視角膜塑型片", "多焦點日拋隱形眼鏡", "治療角膜用軟式隱形眼鏡", "15歲以下學生首次驗光配戴隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01106', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關繼續教育之規定，下列敘述何者正確？①驗光師參加醫學會、學會、公會舉辦之專業相關繼續教育課', '["驗光師受懲戒處分應接受一定時數繼續教育者，不得以醫事人員執業登記及 繼續教育辦法所定應接受之繼續教育抵充", "醫事人員連續歇業期間逾2年，得以申請執業登記前2年內 接受繼續教育課程總積分達六分之一以上之證明文件代之", "驗光師執業，應接受專業課程、專業品質、 專業倫理、專業相關法規課程之繼續教育  ⑤驗光師應邀擔任有公開徵求論文及審查機制之驗光學術研討 會特別演講者，每小時積分採計5點  ⑥領得醫事人員證書逾5年首次申請執業登記，得免檢具繼續教育 之證明文件", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01107', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '隱形眼鏡屬於醫療器材，有關其鏡片及消毒藥水販賣之規定，下列敘述何者正確？', '["隱形眼鏡之清潔液、保養液及保存用產品屬於第一等級醫療器材", "隱形眼鏡之販售於辦理申請藥商登記並領得許可執照後，方准營業", "隱形眼鏡鏡片消毒藥水、保存液之販售業者，應聘專任藥師管理監督", "隱形眼鏡販售許可執照不必懸掛，但應於營業處所保管好，以便主管機關隨時備查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01108', 'optometrist', 'optometrist-moex-110-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光所之規定，下列敘述何者正確？', '["驗光所之設立，應以驗光人員為申請人，向所在地直轄市、縣（市）主管機關申請核准登記，發給開業 執照，始得為之", "驗光所之名稱使用、變更，應以中央主管機關核准者為限。非驗光所，不得使用驗光所或類似之名稱", "驗光所收取驗光費用之標準，由中央主管機關定之。驗光所不得違反收費標準，超額或擅立項目收費", "驗光所之名稱使用與變更、申請條件、程序及設置標準，由直轄市、縣（市）主管機關核定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "a40e2debed64", "answer_pdf_sha1": "f48c7f0ac209", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
